/// Create a new crawl engine with the given configuration.
///
/// If `config` is `null`, uses `CrawlConfig.default()`.
/// Returns an error if the configuration is invalid.
pub fn create_engine(config: Option<CrawlConfig>) -> Result<CrawlEngineHandle, String> {
    kreuzcrawl::create_engine(config.map(kreuzcrawl::CrawlConfig::from))
        .map(|inner| CrawlEngineHandle { inner })
        .map_err(|e| e.to_string())
}

/// Scrape a single URL, returning extracted page data.
pub async fn scrape(engine: CrawlEngineHandle, url: String) -> Result<ScrapeResult, String> {
    kreuzcrawl::scrape(&engine.inner, &url)
        .await
        .map(ScrapeResult::from)
        .map_err(|e| e.to_string())
}

/// Crawl a website starting from `url`, following links up to the configured depth.
pub async fn crawl(engine: CrawlEngineHandle, url: String) -> Result<CrawlResult, String> {
    kreuzcrawl::crawl(&engine.inner, &url)
        .await
        .map(CrawlResult::from)
        .map_err(|e| e.to_string())
}

/// Discover all pages on a website by following links and sitemaps.
pub async fn map_urls(engine: CrawlEngineHandle, url: String) -> Result<MapResult, String> {
    kreuzcrawl::map_urls(&engine.inner, &url)
        .await
        .map(MapResult::from)
        .map_err(|e| e.to_string())
}

/// Scrape multiple URLs concurrently.
pub async fn batch_scrape(engine: CrawlEngineHandle, urls: Vec<String>) -> Result<Vec<BatchScrapeResult>, String> {
    kreuzcrawl::batch_scrape(&engine.inner, urls)
        .await
        .map(|v| v.into_iter().map(BatchScrapeResult::from).collect())
        .map_err(|e| e.to_string())
}

/// Crawl multiple seed URLs concurrently, each following links to configured depth.
pub async fn batch_crawl(engine: CrawlEngineHandle, urls: Vec<String>) -> Result<Vec<BatchCrawlResult>, String> {
    kreuzcrawl::batch_crawl(&engine.inner, urls)
        .await
        .map(|v| v.into_iter().map(BatchCrawlResult::from).collect())
        .map_err(|e| e.to_string())
}

