#[frb]
pub fn create_batch_crawl_result_from_json(json: String) -> Result<BatchCrawlResult, String> {
    serde_json::from_str::<kreuzcrawl::BatchCrawlResult>(&json)
        .map(BatchCrawlResult::from)
        .map_err(|e| e.to_string())
}
